node Task {
    has name: str;
    has minutes: int;
}

walker SumMinutes {
    has total: int = 0;

    can add with Task entry {
        self.total += here.minutes;
        visit [-->];
    }
}

with entry {
    design = Task(name="design", minutes=30);
    build = Task(name="build", minutes=50);
    test = Task(name="test", minutes=20);
    design ++> build;
    build ++> test;
    w = SumMinutes();
    design spawn w;
    print(w.total);
}
